+    // Copy the rest of the data
+    int cur_c = 0;
+    for (size_t d = 0; d < input.fields.size (); ++d)
+    {
+      if ((int)input.fields[d].offset == x_offset || (int)input.fields[d].offset == y_offset || (int)input.fields[d].offset == z_offset)
